import React, { useState, useEffect } from 'react';
import {
    Container,
    Typography,
    Paper,
    Box,
    TextField,
    Button,
    Alert,
    CircularProgress,
    Grid,
    Card,
    CardContent,
    MenuItem
} from '@mui/material';
import { authAPI, statsAPI } from '../services/api';
import { useAuth } from '../contexts/AuthContext';

const Profile = () => {
    const { user, updateUser } = useAuth();
    const [profile, setProfile] = useState(null);
    const [stats, setStats] = useState(null);
    const [loading, setLoading] = useState(true);
    const [editing, setEditing] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');
    const [formData, setFormData] = useState({
        full_name: '',
        age: '',
        weight: '',
        height: '',
        fitness_level: 'Beginner'
    });

    const fitnessLevels = ['Beginner', 'Intermediate', 'Advanced'];

    useEffect(() => {
        fetchProfileAndStats();
    }, []);

    const fetchProfileAndStats = async () => {
        try {
            const [profileRes, statsRes] = await Promise.all([
                authAPI.getProfile(),
                statsAPI.getStats()
            ]);

            setProfile(profileRes.data);
            setStats(statsRes.data);
            setFormData({
                full_name: profileRes.data.full_name || '',
                age: profileRes.data.age || '',
                weight: profileRes.data.weight || '',
                height: profileRes.data.height || '',
                fitness_level: profileRes.data.fitness_level || 'Beginner'
            });
        } catch (err) {
            setError('Failed to load profile data');
        } finally {
            setLoading(false);
        }
    };

    const handleEdit = () => {
        setEditing(true);
        setSuccess('');
        setError('');
    };

    const handleCancel = () => {
        setEditing(false);
        setFormData({
            full_name: profile.full_name || '',
            age: profile.age || '',
            weight: profile.weight || '',
            height: profile.height || '',
            fitness_level: profile.fitness_level || 'Beginner'
        });
    };

    const handleSubmit = async () => {
        try {
            await authAPI.updateProfile(formData);
            setProfile({ ...profile, ...formData });
            updateUser({ username: user.username, ...formData });
            setEditing(false);
            setSuccess('Profile updated successfully!');
            setError('');
        } catch (err) {
            setError('Failed to update profile');
        }
    };

    const handleChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    };

    if (loading) {
        return (
            <Container sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '80vh' }}>
                <CircularProgress />
            </Container>
        );
    }

    return (
        <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
            <Typography variant="h4" gutterBottom>
                Profile
            </Typography>

            {error && (
                <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError('')}>
                    {error}
                </Alert>
            )}

            {success && (
                <Alert severity="success" sx={{ mb: 2 }} onClose={() => setSuccess('')}>
                    {success}
                </Alert>
            )}

            <Grid container spacing={3}>
                <Grid item xs={12} md={6}>
                    <Paper sx={{ p: 3 }}>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
                            <Typography variant="h5">
                                Personal Information
                            </Typography>
                            {!editing && (
                                <Button variant="outlined" onClick={handleEdit}>
                                    Edit Profile
                                </Button>
                            )}
                        </Box>

                        {editing ? (
                            <Box component="form">
                                <TextField
                                    fullWidth
                                    margin="normal"
                                    label="Full Name"
                                    name="full_name"
                                    value={formData.full_name}
                                    onChange={handleChange}
                                />

                                <Box sx={{ display: 'flex', gap: 2, mb: 2 }}>
                                    <TextField
                                        fullWidth
                                        label="Age"
                                        name="age"
                                        type="number"
                                        value={formData.age}
                                        onChange={handleChange}
                                    />
                                    <TextField
                                        fullWidth
                                        label="Weight (kg)"
                                        name="weight"
                                        type="number"
                                        value={formData.weight}
                                        onChange={handleChange}
                                    />
                                    <TextField
                                        fullWidth
                                        label="Height (cm)"
                                        name="height"
                                        type="number"
                                        value={formData.height}
                                        onChange={handleChange}
                                    />
                                </Box>

                                <TextField
                                    select
                                    fullWidth
                                    margin="normal"
                                    label="Fitness Level"
                                    name="fitness_level"
                                    value={formData.fitness_level}
                                    onChange={handleChange}
                                >
                                    {fitnessLevels.map((level) => (
                                        <MenuItem key={level} value={level}>
                                            {level}
                                        </MenuItem>
                                    ))}
                                </TextField>

                                <Box sx={{ display: 'flex', gap: 2, mt: 3 }}>
                                    <Button
                                        variant="contained"
                                        onClick={handleSubmit}
                                        fullWidth
                                    >
                                        Save Changes
                                    </Button>
                                    <Button
                                        variant="outlined"
                                        onClick={handleCancel}
                                        fullWidth
                                    >
                                        Cancel
                                    </Button>
                                </Box>
                            </Box>
                        ) : (
                            <Box>
                                <Typography variant="body1" gutterBottom>
                                    <strong>Username:</strong> {user?.username}
                                </Typography>
                                <Typography variant="body1" gutterBottom>
                                    <strong>Email:</strong> {profile?.email}
                                </Typography>
                                <Typography variant="body1" gutterBottom>
                                    <strong>Full Name:</strong> {profile?.full_name || 'Not set'}
                                </Typography>
                                <Typography variant="body1" gutterBottom>
                                    <strong>Age:</strong> {profile?.age || 'Not set'}
                                </Typography>
                                <Typography variant="body1" gutterBottom>
                                    <strong>Weight:</strong> {profile?.weight ? `${profile.weight} kg` : 'Not set'}
                                </Typography>
                                <Typography variant="body1" gutterBottom>
                                    <strong>Height:</strong> {profile?.height ? `${profile.height} cm` : 'Not set'}
                                </Typography>
                                <Typography variant="body1">
                                    <strong>Fitness Level:</strong> {profile?.fitness_level || 'Not set'}
                                </Typography>
                            </Box>
                        )}
                    </Paper>
                </Grid>

                <Grid item xs={12} md={6}>
                    <Paper sx={{ p: 3 }}>
                        <Typography variant="h5" gutterBottom>
                            Fitness Statistics
                        </Typography>

                        {stats ? (
                            <Grid container spacing={2}>
                                <Grid item xs={6}>
                                    <Card>
                                        <CardContent>
                                            <Typography color="textSecondary" gutterBottom>
                                                Total Activities
                                            </Typography>
                                            <Typography variant="h4">
                                                {stats.total_activities || 0}
                                            </Typography>
                                        </CardContent>
                                    </Card>
                                </Grid>
                                <Grid item xs={6}>
                                    <Card>
                                        <CardContent>
                                            <Typography color="textSecondary" gutterBottom>
                                                This Week
                                            </Typography>
                                            <Typography variant="h4">
                                                {stats.weekly_stats?.activity_count || 0}
                                            </Typography>
                                        </CardContent>
                                    </Card>
                                </Grid>
                                <Grid item xs={6}>
                                    <Card>
                                        <CardContent>
                                            <Typography color="textSecondary" gutterBottom>
                                                Weekly Duration
                                            </Typography>
                                            <Typography variant="h4">
                                                {stats.weekly_stats?.total_duration || 0}
                                                <Typography variant="caption" color="textSecondary">
                                                    {' '}min
                                                </Typography>
                                            </Typography>
                                        </CardContent>
                                    </Card>
                                </Grid>
                                <Grid item xs={6}>
                                    <Card>
                                        <CardContent>
                                            <Typography color="textSecondary" gutterBottom>
                                                Calories Burned
                                            </Typography>
                                            <Typography variant="h4">
                                                {stats.weekly_stats?.total_calories?.toFixed(0) || 0}
                                            </Typography>
                                        </CardContent>
                                    </Card>
                                </Grid>

                                <Grid item xs={12}>
                                    <Paper sx={{ p: 2, mt: 2 }}>
                                        <Typography variant="h6" gutterBottom>
                                            Activity Distribution (This Week)
                                        </Typography>
                                        {Object.keys(stats.activity_distribution || {}).length > 0 ? (
                                            Object.entries(stats.activity_distribution).map(([type, count]) => (
                                                <Box key={type} sx={{ mb: 1 }}>
                                                    <Typography variant="body2">
                                                        {type}: {count} activities
                                                    </Typography>
                                                </Box>
                                            ))
                                        ) : (
                                            <Typography variant="body2" color="textSecondary">
                                                No activities this week
                                            </Typography>
                                        )}
                                    </Paper>
                                </Grid>
                            </Grid>
                        ) : (
                            <Typography variant="body2" color="textSecondary">
                                Loading statistics...
                            </Typography>
                        )}
                    </Paper>
                </Grid>
            </Grid>
        </Container>
    );
};

export default Profile;
